func todayDate() string {
	return time.Now().Format("2006-01-02")
}

func tomorrowDate() string {
	return time.Now().AddDate(0, 0, 1).Format("2006-01-02")
}

func nextMondayDate() string {
	t := time.Now()
	daysUntilMonday := (8 - int(t.Weekday())) % 7
	if daysUntilMonday == 0 {
		daysUntilMonday = 7
	}
	return t.AddDate(0, 0, daysUntilMonday).Format("2006-01-02")
}

func isOverdue(due string) bool {
	return due != "" && due < todayDate()
}

func rescheduleVals(due string, listTitle string) string {
	if listTitle != "" {
		return `{"due": "` + due + `", "listTitle": "` + listTitle + `"}`
	}
	return `{"due": "` + due + `"}`
}

